const text = $('Webhook').first().json.body.payload || "";

// Trim leading spaces just in case
const trimmedText = text.trim();

// Case sensitive check for "Contact Information:" at the start
const isContactInfo = trimmedText.startsWith("Contact Information:");

return [
  {
    json: {
      isContactInfo
    }
  }
];

const timezone = query.timezone;

const now = new Date();

const options = { timeZone: timezone, hour12: false };
const formatterDate = new Intl.DateTimeFormat('en-US', { ...options, year: 'numeric', month: '2-digit', day: '2-digit' });
const formatterTime = new Intl.DateTimeFormat('en-US', { ...options, hour: '2-digit', minute: '2-digit', second: '2-digit' });
const formatterDay = new Intl.DateTimeFormat('en-US', { ...options, weekday: 'long' });

const dateParts = formatterDate.formatToParts(now).reduce((acc, part) => {
  if (part.type !== 'literal') acc[part.type] = part.value;
  return acc;
}, {});

const timeParts = formatterTime.formatToParts(now).reduce((acc, part) => {
  if (part.type !== 'literal') acc[part.type] = part.value;
  return acc;
}, {});

const dayOfWeek = formatterDay.format(now);

const output = {
  year: parseInt(dateParts.year),
  month: parseInt(dateParts.month),
  day: parseInt(dateParts.day),
  hour: parseInt(timeParts.hour),
  minute: parseInt(timeParts.minute),
  seconds: parseInt(timeParts.second),
  milliSeconds: now.getMilliseconds(),
  dateTime: now.toISOString(),
  date: `${dateParts.month}/${dateParts.day}/${dateParts.year}`,
  time: `${timeParts.hour}:${timeParts.minute}`,
  timeZone: timezone,
  dayOfWeek: dayOfWeek,
  dstActive: false
};

return JSON.stringify(output);

