// Get the data array from Supabase response
const input = $input.all()[0].json;

// Check if data exists and is an array
let prompts = [];
if (input.data && Array.isArray(input.data)) {
  prompts = input.data;
} else if (Array.isArray(input)) {
  prompts = input;
} else {
  prompts = $input.all().map(item => item.json);
}

// Sort by Id in ascending order (0-11) - note the capital 'I'
prompts.sort((a, b) => {
  return a.Id - b.Id;
});

// Return in N8N format
return prompts.map(prompt => ({ json: prompt }));

